import React, { useState, useEffect, useMemo } from 'react';

const Icon = ({ name }) => {
  const icons = {
    telegram: (
      <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm4.64 6.8c-.15 1.58-.8 5.42-1.13 7.19-.14.75-.42 1-.68 1.03-.58.05-1.02-.38-1.58-.75-.88-.58-1.38-.94-2.23-1.5-.99-.65-.35-1.01.22-1.59.15-.15 2.71-2.48 2.76-2.69.01-.03.01-.14-.07-.2-.08-.06-.19-.04-.27-.02-.11.02-1.93 1.23-5.46 3.62-.51.35-.98.53-1.39.52-.46-.01-1.33-.26-1.98-.48-.8-.27-1.43-.42-1.37-.89.03-.25.38-.51 1.03-.78 4.04-1.76 6.74-2.92 8.09-3.48 3.85-1.6 4.64-1.88 5.17-1.89.11 0 .37.03.54.17.14.12.18.28.2.45-.02.07-.02.13-.03.19z"/>
    ),
    phone: (
      <path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"/>
    )
  };

  return (
    <svg viewBox="0 0 24 24" width="18" height="18" fill="currentColor">
      {icons[name]}
    </svg>
  );
};

const App = () => {
  const [filter, setFilter] = useState('Все');
  const [isScrolled, setIsScrolled] = useState(false);
  const [showArchive, setShowArchive] = useState(false);

  const categories = ['Все', 'Айдентика', 'Логотипы', 'Веб-дизайн', 'Печатная графика'];

  const projects = useMemo(() => ({
    featured: [
      { id: 'f1', title: "Проект айдентики", cat: "Айдентика", year: 2025, img: "https://images.unsplash.com/photo-1626785774573-4b799315345d?auto=format&fit=crop&q=80&w=800" },
      { id: 'f2', title: "Веб-интерфейс", cat: "Веб-дизайн", year: 2025, img: "https://images.unsplash.com/photo-1551288049-bbbda5366392?auto=format&fit=crop&q=80&w=800" },
      { id: 'f3', title: "Логотип и стиль", cat: "Логотипы", year: 2025, img: "https://images.unsplash.com/photo-1572044162444-ad60f128bde2?auto=format&fit=crop&q=80&w=800" },
    ],
    archive: [
      { id: 'a1', title: "Учебный логотип", cat: "Логотипы", year: 2024, img: "https://images.unsplash.com/photo-1614850523296-d8c1af93d400?auto=format&fit=crop&q=80&w=800" },
      { id: 'a2', title: "Графическая работа", cat: "Печатная графика", year: 2024, img: "https://images.unsplash.com/photo-1561070791-2526d30994b5?auto=format&fit=crop&q=80&w=800" },
      { id: 'a3', title: "Макет полиграфии", cat: "Печатная графика", year: 2024, img: "https://images.unsplash.com/photo-1586075010923-2dd4570fb338?auto=format&fit=crop&q=80&w=800" },
      { id: 'a4', title: "Первый лендинг", cat: "Веб-дизайн", year: 2024, img: "https://images.unsplash.com/photo-1547658719-da2b51169166?auto=format&fit=crop&q=80&w=800" },
    ]
  }), []);

  const filterFn = (p) => filter === 'Все' || p.cat === filter;
  const filteredFeatured = projects.featured.filter(filterFn);
  const filteredArchive = projects.archive.filter(filterFn);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollTo = (id) => {
    const el = document.getElementById(id);
    if (el) {
      const offset = 140; 
      window.scrollTo({
        top: el.offsetTop - offset,
        behavior: 'smooth'
      });
    }
  };

  return (
    <div className="portfolio-root">
      {/* Header */}
      <div className="header-wrapper">
        <header className={`header-main ${isScrolled ? 'scrolled' : ''}`}>
          <div className="container header-content">
            <div className="logo">АЛЕКСАНДРА БЛАГОДАТСКИХ</div>

            <nav className="nav-links">
              <button onClick={() => scrollTo('projects')}>Проекты</button>
              <button onClick={() => scrollTo('about')}>Обо мне</button>
              <button onClick={() => scrollTo('contact')}>Контакты</button>
            </nav>

            <div className="social-icons">
              <a href="https://t.me/renraie" target="_blank" rel="noreferrer"><Icon name="telegram"/></a>
              <a href="tel:+79639960003"><Icon name="phone"/></a>
            </div>
          </div>
        </header>

        <div className="filter-bar">
          <div className="container filter-content">
            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => setFilter(cat)}
                className={`filter-btn ${filter === cat ? 'active' : ''}`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Hero */}
      <section id="about" className="hero container">
        <h1 className="hero-title">
          Учусь делать <span className="accent">красивый</span> и понятный дизайн.
        </h1>
        <p className="hero-subtitle">
          Привет, я Александра. Изучаю айдентику, логотипы и веб-дизайн. 
          Здесь я собираю свои работы.
        </p>
      </section>

      {/* Projects */}
      <main id="projects" className="container main-content">
        <div className="section-projects">
          <h2 className="section-label">Избранные проекты</h2>
          <div className="projects-grid">
            {filteredFeatured.map((project) => (
              <div key={project.id} className="project-card">
                <div className="img-wrapper">
                  <img src={project.img} alt={project.title} />
                  <div className="overlay" />
                </div>
                <div className="project-info">
                  <div>
                    <h3>{project.title}</h3>
                    <p className="cat-label">{project.cat}</p>
                  </div>
                  <span className="year-label">{project.year}</span>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="archive-section">
          <button onClick={() => setShowArchive(!showArchive)} className="btn-archive">
            {showArchive ? '— Свернуть' : '+ Показать архив'}
          </button>

          {showArchive && (
            <div className="archive-grid">
              {filteredArchive.map((project) => (
                <div key={project.id} className="archive-card">
                  <div className="archive-img-wrapper">
                      <img src={project.img} alt={project.title} />
                  </div>
                  <h4>{project.title}</h4>
                  <p className="cat-label">{project.cat}</p>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>

      {/* Footer */}
      <footer id="contact" className="footer">
        <div className="container footer-content">
          <div className="footer-left">
            <h2 className="footer-title">Связаться со мной</h2>
            <div className="contact-links">
              <a href="tel:+79639960003">8 (963) 996-00-03</a>
              <a href="https://t.me/renraie" target="_blank" rel="noreferrer">Telegram: @renraie</a>
            </div>
          </div>
          <div className="copyright">
            © 2024—2026 Alexandra Blagodatskikh
          </div>
        </div>
      </footer>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;1,400&display=swap');

        /* Базовые настройки */
        .portfolio-root {
          background-color: #0d0d0f;
          color: #e0e0e6;
          min-height: 100vh;
          font-family: sans-serif;
          margin: 0;
          padding: 0;
        }

        .container {
          max-width: 1200px;
          margin: 0 auto;
          padding: 0 24px;
        }

        /* Шапка */
        .header-wrapper {
          position: fixed;
          top: 0;
          width: 100%;
          z-index: 100;
        }

        .header-main {
          background: rgba(13, 13, 15, 0.8);
          backdrop-filter: blur(20px);
          border-bottom: 1px solid rgba(255, 255, 255, 0.05);
          padding: 24px 0;
          transition: all 0.3s;
        }

        .header-main.scrolled { padding: 16px 0; }

        .header-content {
          display: flex;
          justify-content: space-between;
          align-items: center;
        }

        .logo {
          font-weight: bold;
          letter-spacing: 0.2em;
          color: #ffb3d9;
          text-transform: uppercase;
        }

        .nav-links { display: none; }
        @media (min-width: 768px) {
          .nav-links { display: flex; gap: 32px; }
        }

        .nav-links button {
          background: none; border: none; color: rgba(255,255,255,0.4);
          text-transform: uppercase; font-size: 10px; letter-spacing: 0.2em;
          cursor: pointer; transition: color 0.3s;
        }
        .nav-links button:hover { color: #fff; }

        .social-icons { display: flex; gap: 20px; }
        .social-icons a { color: inherit; transition: color 0.3s, transform 0.3s; display: inline-block; }
        .social-icons a:hover { color: #ffb3d9; transform: scale(1.1); }

        .filter-bar {
          background: rgba(13, 13, 15, 0.6);
          backdrop-filter: blur(10px);
          border-bottom: 1px solid rgba(255, 255, 255, 0.05);
          padding: 16px 0;
        }

        .filter-content { display: flex; gap: 8px; flex-wrap: wrap; }

        .filter-btn {
          padding: 6px 16px; border-radius: 99px; font-size: 10px;
          text-transform: uppercase; border: 1px solid rgba(255,255,255,0.1);
          background: rgba(255,255,255,0.05); color: rgba(255,255,255,0.4);
          cursor: pointer; transition: all 0.3s;
        }

        .filter-btn.active {
          background: #ffb3d9; border-color: #ffb3d9; color: #2d1b24;
        }

        /* Hero */
        .hero { padding-top: 280px; padding-bottom: 100px; }
        .hero-title {
          font-family: 'Playfair Display', serif;
          font-size: clamp(32px, 8vw, 100px);
          font-weight: 300; line-height: 1.1; margin-bottom: 32px;
        }
        .accent { font-style: italic; color: #ffb3d9; }
        .hero-subtitle {
          font-size: 20px; color: rgba(255,255,255,0.4); max-width: 600px; line-height: 1.6;
        }

        /* Сетка проектов */
        .projects-grid {
          display: grid;
          grid-template-columns: 1fr;
          gap: 48px;
        }
        @media (min-width: 768px) { .projects-grid { grid-template-columns: 1fr 1fr; } }

        .section-label {
          font-size: 10px; text-transform: uppercase; letter-spacing: 0.4em;
          color: rgba(255,255,255,0.2); margin-bottom: 40px;
        }

        .project-card { cursor: pointer; }
        .img-wrapper {
          position: relative; border-radius: 32px; overflow: hidden;
          aspect-ratio: 4/3; background: rgba(255,255,255,0.05);
          border: 1px solid rgba(255,255,255,0.05); margin-bottom: 24px;
          transition: border-color 0.5s;
        }
        .project-card:hover .img-wrapper { border-color: rgba(255,179,217,0.3); }

        .img-wrapper img {
          width: 100%; height: 100%; object-fit: cover;
          transition: transform 1s;
        }
        .project-card:hover img { transform: scale(1.05); }

        .project-info { display: flex; justify-content: space-between; align-items: flex-end; }
        .project-info h3 { margin: 0 0 4px 0; font-size: 20px; transition: color 0.3s; }
        .project-card:hover h3 { color: #ffb3d9; }

        .cat-label { font-size: 10px; text-transform: uppercase; color: rgba(255,255,255,0.3); margin: 0; }
        .year-label { font-size: 10px; color: rgba(255,255,255,0.1); }

        /* Архив */
        .archive-section { margin-top: 40px; border-top: 1px solid rgba(255,255,255,0.05); padding-top: 40px; }
        .btn-archive {
          background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1);
          color: rgba(255,255,255,0.4); padding: 12px 32px; border-radius: 99px;
          cursor: pointer; transition: all 0.5s; font-size: 10px; text-transform: uppercase;
        }
        .btn-archive:hover { border-color: #ffb3d9; color: #ffb3d9; }

        .archive-grid {
          display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
          gap: 32px; margin-top: 48px;
          animation: slideUp 0.7s ease-out;
        }
        @keyframes slideUp {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }

        .archive-card h4 { margin: 16px 0 4px 0; color: rgba(255,255,255,0.6); }
        .archive-img-wrapper { border-radius: 16px; overflow: hidden; aspect-ratio: 1/1; }
        .archive-img-wrapper img { width: 100%; height: 100%; object-fit: cover; opacity: 0.4; transition: opacity 0.5s; }
        .archive-card:hover img { opacity: 1; }

        /* Footer */
        .footer { background: #0d0d0f; border-top: 1px solid rgba(255,255,255,0.05); padding: 100px 0; margin-top: 100px; }
        .footer-content { display: flex; flex-direction: column; gap: 60px; }
        @media (min-width: 768px) { .footer-content { flex-direction: row; justify-content: space-between; align-items: flex-end; } }

        .footer-title { font-family: 'Playfair Display', serif; font-size: 40px; font-style: italic; color: #ffb3d9; margin-bottom: 40px; }
        .contact-links { display: flex; flex-direction: column; gap: 24px; }
        .contact-links a { font-size: 24px; color: inherit; text-decoration: none; border-bottom: 1px solid rgba(255,255,255,0.05); padding-bottom: 8px; transition: color 0.3s; }
        .contact-links a:hover { color: #ffb3d9; }
        .copyright { font-size: 10px; text-transform: uppercase; color: rgba(255,255,255,0.1); letter-spacing: 0.4em; }

        html { scroll-behavior: smooth; }
      `}</style>
    </div>
  );
};

export default App;
